using System.Reflection;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Xml.Linq;
using System.IO;

class Program
{
    static void Main()
    {
        var dlls = new[]
        {
            new { Path = "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net10.0/Microsoft.Extensions.AI.dll", Name = "Microsoft.Extensions.AI" },
            new { Path = "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.0/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll", Name = "Microsoft.Extensions.AI.Abstractions" },
            new { Path = "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.5.0/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll", Name = "Microsoft.Extensions.AI.OpenAI" },
            new { Path = "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll", Name = "Microsoft.Agents.AI" },
        };

        foreach (var dll in dlls)
        {
            Console.WriteLine("\n" + new string('=', 100));
            Console.WriteLine($"ASSEMBLY: {dll.Name}");
            Console.WriteLine(new string('=', 100));

            try
            {
                var assembly = Assembly.LoadFrom(dll.Path);
                var types = assembly.GetTypes().Where(t => t.IsPublic).OrderBy(t => t.Name).ToList();

                Console.WriteLine($"Total Public Types: {types.Count}\n");

                foreach (var type in types)
                {
                    DumpType(type);
                }

                // Try to load XML docs
                var xmlPath = Path.ChangeExtension(dll.Path, ".xml");
                if (File.Exists(xmlPath))
                {
                    Console.WriteLine("\n" + new string('-', 100));
                    Console.WriteLine("XML DOCUMENTATION:");
                    Console.WriteLine(new string('-', 100));
                    try
                    {
                        var doc = XDocument.Load(xmlPath);
                        var members = doc.Descendants("member").Take(50);
                        foreach (var member in members)
                        {
                            var name = member.Attribute("name")?.Value;
                            var summary = member.Element("summary")?.Value?.Trim();
                            var remarks = member.Element("remarks")?.Value?.Trim();
                            if (!string.IsNullOrEmpty(name) && !string.IsNullOrEmpty(summary))
                            {
                                Console.WriteLine($"\n{name}:");
                                Console.WriteLine($"  {summary}");
                                if (!string.IsNullOrEmpty(remarks))
                                {
                                    Console.WriteLine($"  Remarks: {remarks}");
                                }
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        Console.WriteLine($"Error reading XML: {ex.Message}");
                    }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error loading {dll.Name}: {ex.Message}");
            }
        }
    }

    static void DumpType(Type type)
    {
        var keywords = new[] { "IChatClient", "ChatOptions", "AIFunction", "AITool", "ChatClientBuilder", "FunctionInvoking", "ChatAgent", "OpenAIChatClient" };
        bool isKeyword = keywords.Any(k => type.Name.Contains(k));

        var marker = isKeyword ? "*** " : "";

        Console.WriteLine($"{marker}{type.FullName}");

        // Constructors
        var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance).OrderBy(c => c.GetParameters().Length);
        foreach (var ctor in constructors)
        {
            var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"  ctor({@params})");
        }

        // Properties
        var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .OrderBy(p => p.Name);
        foreach (var prop in properties)
        {
            var getSet = "";
            if (prop.CanRead) getSet += "get";
            if (prop.CanWrite) getSet += (getSet.Length > 0 ? "|set" : "set");
            Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} [{getSet}]");
        }

        // Methods
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .Where(m => !m.IsSpecialName)
            .OrderBy(m => m.Name);
        foreach (var method in methods)
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => 
            {
                var typeName = p.ParameterType.Name;
                if (p.ParameterType.IsGenericType)
                    typeName = p.ParameterType.Name.Split('`')[0] + "<...>";
                return $"{typeName} {p.Name}";
            }));
            var returnType = method.ReturnType.Name;
            if (method.ReturnType.IsGenericType)
                returnType = method.ReturnType.Name.Split('`')[0] + "<...>";
            Console.WriteLine($"  {returnType} {method.Name}({@params})");
        }

        // Nested Types
        var nestedTypes = type.GetNestedTypes(BindingFlags.Public).OrderBy(t => t.Name);
        foreach (var nested in nestedTypes)
        {
            Console.WriteLine($"  [Nested] {nested.Name}");
        }

        Console.WriteLine();
    }
}
