using System;
using System.Reflection;
using System.Collections.Generic;
using System.Linq;
using System.IO;

class Program
{
    static void Main()
    {
        var dllPaths = new[]
        {
            "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.0/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.0/lib/net10.0/Microsoft.Extensions.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.5.0/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll",
            "/home/runner/.nuget/packages/microsoft.agents.ai/1.3.0/lib/net10.0/Microsoft.Agents.AI.dll",
        };

        foreach (var dllPath in dllPaths)
        {
            if (!File.Exists(dllPath))
            {
                Console.WriteLine($"Not found: {dllPath}");
                continue;
            }

            Console.WriteLine("\n" + new string('=', 120));
            Console.WriteLine($"ASSEMBLY: {Path.GetFileNameWithoutExtension(dllPath)}");
            Console.WriteLine(new string('=', 120));

            try
            {
                var assembly = Assembly.LoadFrom(dllPath);
                var types = assembly.GetTypes().Where(t => t.IsPublic).OrderBy(t => t.Name).ToList();

                Console.WriteLine($"Total Public Types: {types.Count}\n");

                foreach (var type in types)
                {
                    DumpType(type);
                }
            }
            catch (ReflectionTypeLoadException rex)
            {
                Console.WriteLine($"Partial load error: {rex.Message}");
                foreach (var ex in rex.LoaderExceptions.Take(5))
                {
                    Console.WriteLine($"  - {ex?.Message}");
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"Error: {ex.Message}");
                Console.WriteLine($"Stack: {ex.StackTrace}");
            }
        }
    }

    static void DumpType(Type type)
    {
        var keywords = new[] { "IChatClient", "ChatOptions", "AIFunction", "AITool", "ChatClientBuilder", "FunctionInvoking", "ChatAgent", "OpenAIChatClient", "Agent" };
        bool isKeyword = keywords.Any(k => type.Name.Contains(k));

        var marker = isKeyword ? "*** " : "";

        string typeKind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract class" : type.IsEnum ? "enum" : "class";

        Console.WriteLine($"{marker}{typeKind} {type.FullName}");

        // Base type
        if (type.BaseType != null && type.BaseType != typeof(object) && type.BaseType != typeof(ValueType))
        {
            Console.WriteLine($"  : {type.BaseType.Name}");
        }

        // Interfaces
        var interfaces = type.GetInterfaces().Where(i => !i.IsGenericTypeDefinition);
        foreach (var iface in interfaces)
        {
            Console.WriteLine($"  implements {iface.Name}");
        }

        // Constructors
        var constructors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance).OrderBy(c => c.GetParameters().Length);
        foreach (var ctor in constructors)
        {
            var @params = string.Join(", ", ctor.GetParameters().Select(p => FormatType(p.ParameterType)));
            Console.WriteLine($"  ctor({@params})");
        }

        // Properties
        var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
            .OrderBy(p => p.Name);
        foreach (var prop in properties)
        {
            var getSet = "";
            if (prop.CanRead) getSet += "get";
            if (prop.CanWrite) getSet += (getSet.Length > 0 ? "|set" : "set");
            Console.WriteLine($"  {FormatType(prop.PropertyType)} {prop.Name} [{getSet}]");
        }

        // Methods (no special names, no get/set)
        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
            .Where(m => !m.IsSpecialName)
            .OrderBy(m => m.Name);
        foreach (var method in methods)
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => FormatType(p.ParameterType) + " " + p.Name));
            Console.WriteLine($"  {FormatType(method.ReturnType)} {method.Name}({@params})");
        }

        Console.WriteLine();
    }

    static string FormatType(Type t)
    {
        if (t == null) return "void";

        // Handle generic types
        if (t.IsGenericType)
        {
            var baseName = t.Name.Split('`')[0];
            var args = t.GetGenericArguments();
            var argNames = string.Join(", ", args.Select(FormatType));
            return $"{baseName}<{argNames}>";
        }

        // Handle arrays
        if (t.IsArray)
        {
            return FormatType(t.GetElementType()) + "[]";
        }

        return t.Name;
    }
}
