using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var openAiModel = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");

if (string.IsNullOrWhiteSpace(openAiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Tool instances ----------------------------------------------------------

var notebook = new Notebook();

// --- Chat client pipeline (inner → outer) ------------------------------------
// OpenAIChatClient  →  FunctionInvokingChatClient
//   so the model can call our tools and the pipeline auto-invokes them.

IChatClient chatClient = new OpenAIClient(openAiKey)
    .GetChatClient(openAiModel)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- Agent -------------------------------------------------------------------

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

const string instructions = """
    You are a research agent. Your goal is to thoroughly research the topic the
    user gives you and produce a well-organized summary.

    Follow this workflow:
    1. Break the topic into 2-4 key subtopics or questions.
    2. For each subtopic, use the web_search tool to find relevant information.
    3. After each search, use the add_note tool to save the most important findings
       with the subtopic as the category.
    4. When you have gathered enough information, use get_notes to review everything
       you have collected.
    5. Finally, write a comprehensive summary that synthesizes all your notes into
       a clear, well-structured report with sections and key takeaways.

    Always cite where information came from when possible.
    """;

ChatClientAgent agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// --- Run the agent -----------------------------------------------------------

var session = await agent.CreateSessionAsync();
AgentResponse response = await agent.RunAsync(topic, session);

Console.WriteLine("═══════════════════════════════════════════════════════════════");
Console.WriteLine("                     RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════════════════════════");

return 0;

// --- Helpers -----------------------------------------------------------------

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }

    return input;
}

