            if (!string.IsNullOrWhiteSpace(title))
                results.Add(new SearchResult(StripHtml(title).Trim(), StripHtml(snippet).Trim(), href));

            pos = snippetIdx >= 0 ? snippetIdx + 1 : anchorIdx + 1;
        }

        return results;
