        var closeTag = html.IndexOf('<', gt + 1);
        if (closeTag < 0) return html[(gt + 1)..];

        return html[(gt + 1)..closeTag];
    }

    private static string StripHtml(string s)
    {
        var sb = new StringBuilder(s.Length);
        var inside = false;
        foreach (var c in s)
        {
            switch (c)
            {
                case '<': inside = true; break;
                case '>': inside = false; break;
                default:
                    if (!inside) sb.Append(c);
                    break;
            }
        }

        return System.Net.WebUtility.HtmlDecode(sb.ToString());
    }

