 /// <summary>Simulated web-search tool that queries the web for a given query.</summary>
 static class WebSearchTool
 {
     [Description("Searches the web for the given query and returns a list of result snippets.")]
     public static async Task<string> SearchAsync(
         [Description("The search query string")] string query)
     {
         // Use a real search API when available; this implementation uses
         // DuckDuckGo's instant-answer HTML endpoint as a lightweight fallback.
         try
         {
             using var http = new HttpClient();
             http.DefaultRequestHeaders.UserAgent.ParseAdd(
                 "ResearchAgent/1.0 (compatible; bot)");

             var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
             var html = await http.GetStringAsync(url);

             var snippets = ParseSnippets(html);
             if (snippets.Count == 0)
                 return $"No results found for: {query}";

             var sb = new StringBuilder();
             sb.AppendLine($"Search results for: {query}");
             sb.AppendLine();
             for (var i = 0; i < snippets.Count; i++)
             {
                 sb.AppendLine($"[{i + 1}] {snippets[i].Title}");
                 sb.AppendLine($"    {snippets[i].Snippet}");
                 sb.AppendLine($"    URL: {snippets[i].Url}");
                 sb.AppendLine();
             }

             return sb.ToString();
         }
         catch (Exception ex)
         {
             return $"Search failed ({ex.Message}). The agent should proceed with available information.";
         }
     }

     private static List<SearchResult> ParseSnippets(string html)
     {
         var results = new List<SearchResult>();
         const int maxResults = 5;

         // Parse <a class="result__a"> for titles/URLs and
         // <a class="result__snippet"> for snippet text.
         var pos = 0;
         while (results.Count < maxResults)
         {
             var anchorIdx = html.IndexOf("class=\"result__a\"", pos, StringComparison.Ordinal);
             if (anchorIdx < 0) break;

             var title = ExtractTagContent(html, anchorIdx);
             var href = ExtractHref(html, anchorIdx);

             var snippetIdx = html.IndexOf("class=\"result__snippet\"", anchorIdx, StringComparison.Ordinal);
             var snippet = snippetIdx >= 0 ? ExtractTagContent(html, snippetIdx) : "";

             if (!string.IsNullOrWhiteSpace(title))
                 results.Add(new SearchResult(StripHtml(title).Trim(), StripHtml(snippet).Trim(), href));

             pos = snippetIdx >= 0 ? snippetIdx + 1 : anchorIdx + 1;
         }

         return results;
     }

     private static string ExtractHref(string html, int fromIndex)
     {
         // Walk backwards from fromIndex to find the opening <a, then find href="..."
         var aStart = html.LastIndexOf("<a ", fromIndex, Math.Min(fromIndex, 300), StringComparison.Ordinal);
         if (aStart < 0) return "";

         var hrefIdx = html.IndexOf("href=\"", aStart, StringComparison.Ordinal);
         if (hrefIdx < 0 || hrefIdx > fromIndex + 200) return "";

         hrefIdx += 6;
         var hrefEnd = html.IndexOf('"', hrefIdx);
         return hrefEnd > hrefIdx ? html[hrefIdx..hrefEnd] : "";
     }

     private static string ExtractTagContent(string html, int attrIndex)
     {
         var gt = html.IndexOf('>', attrIndex);
         if (gt < 0) return "";

         var closeTag = html.IndexOf('<', gt + 1);
         if (closeTag < 0) return html[(gt + 1)..];

         return html[(gt + 1)..closeTag];
     }

     private static string StripHtml(string s)
     {
         var sb = new StringBuilder(s.Length);
         var inside = false;
         foreach (var c in s)
         {
             switch (c)
             {
                 case '<': inside = true; break;
                 case '>': inside = false; break;
                 default:
                     if (!inside) sb.Append(c);
                     break;
             }
         }

         return System.Net.WebUtility.HtmlDecode(sb.ToString());
     }

     private record SearchResult(string Title, string Snippet, string Url);
 }

 /// <summary>Simple in-memory notebook that the agent uses to accumulate findings.</summary>
 sealed class Notebook
 {
     private readonly List<Note> _notes = [];

     [Description("Saves a research note under a given category. Use this to record important findings.")]
     public string AddNote(
         [Description("A short category label (e.g. 'History', 'Key People')")] string category,
         [Description("The content of the note")] string content)
     {
