         foreach (var group in _notes.GroupBy(n => n.Category))
         {
             sb.AppendLine($"## {group.Key}");
             foreach (var note in group)
                 sb.AppendLine($"- {note.Content}");
             sb.AppendLine();
         }

         return sb.ToString();
     }

     private record Note(string Category, string Content, DateTime Timestamp);
 }

